import type { Metadata } from "next";
import ShippingAllocation from "./ShippingAllocation";

export const metadata: Metadata = {
  title: "出荷 / 在庫引当 | ぐんじょう WMS",
  description:
    "出荷オーダへの在庫引当画面。受注オーダ一覧（品番・受注数・出荷予定日・得意先・引当状況〔未引当 / 一部引当 / 引当済 / 欠品〕）と出荷遅延リスク、品番別の受注数 vs 引当可能在庫 vs 安全在庫、引当アクション（数量指定 / 自動引当 / 解除）と『引当後』ライブ再計算プレビュー、欠品サマリ／アラート、引当済明細のスキャンによる出荷指示（ピッキング）引き渡しを備えた、出荷コーディネーター向けの在庫引当ワークスペースです。",
};

export default function ShippingAllocationPage() {
  return <ShippingAllocation />;
}

// 出荷 / 在庫引当 — domain types and seed data.
// A logistics coordinator allocates available stock to sales orders, spots
// shortages, and releases shipments. All quantities are in pieces (個).

export type AllocStatus = "unallocated" | "partial" | "allocated" | "shortage";

export interface Sku {
  /** 品番 */
  code: string;
  /** 品名 */
  name: string;
  /** 物理在庫（実在庫） */
  onHand: number;
  /** 他オーダーへ既に引当済の数量 */
  committedElsewhere: number;
  /** 安全在庫（これを割ると補充トリガ） */
  safetyStock: number;
  /** ロケーション棚番 */
  location: string;
  /** JAN/バーコード（出荷指示スキャン照合用） */
  barcode: string;
}

export interface OrderLine {
  /** 受注明細ID */
  id: string;
  /** 出荷オーダ番号 */
  orderNo: string;
  /** 得意先 */
  customer: string;
  /** 品番 */
  skuCode: string;
  /** 受注数 */
  orderedQty: number;
  /** 現在この明細へ引当済の数量（永続化済） */
  allocatedQty: number;
  /** 出荷予定日 (ISO) */
  dueDate: string;
  /** 優先度 */
  priority: "high" | "normal";
  /** 出荷指示（ピッキング）へ引き渡し済か */
  released: boolean;
}

// 「今日」を固定して due-date リスクを決定的にする（SSR/CSR 一致のため）。
