    priority: "normal",
    released: true,
  },
];

// ---- 派生ロジック（純粋関数：テーブル / メーター / サマリ全てで共有） ----

/** SKU の引当可能在庫（ATP, Available To Promise） = 実在庫 − 他オーダー引当 − この画面で既に引当済の合計 */
export function availableToPromise(
  sku: Sku,
  allocatedToThisScreen: number
): number {
  return sku.onHand - sku.committedElsewhere - allocatedToThisScreen;
}

/** 明細の引当状況を、現在の引当数と受注数から判定。 */
export function lineStatus(
  orderedQty: number,
  allocatedQty: number,
  skuShortfall: number
): AllocStatus {
  if (allocatedQty >= orderedQty) return "allocated";
  // この明細を満たせない & その不足が SKU 在庫起因なら欠品。
  if (allocatedQty < orderedQty && skuShortfall > 0) return "shortage";
  if (allocatedQty > 0) return "partial";
  return "unallocated";
}

export const STATUS_META: Record<
  AllocStatus,
  { label: string; symbol: string; badge: "success" | "warning" | "destructive" | "secondary" }
> = {
  allocated: { label: "引当済", symbol: "●", badge: "success" },
  partial: { label: "一部引当", symbol: "◐", badge: "warning" },
  unallocated: { label: "未引当", symbol: "○", badge: "secondary" },
  shortage: { label: "欠品", symbol: "▲", badge: "destructive" },
};

/** 出荷予定日が当日以前なら遅延リスク。 */
export function isAtRisk(dueDate: string, status: AllocStatus): boolean {
  if (status === "allocated") return false;
  return dueDate <= TODAY;
}

export function daysUntil(dueDate: string): number {
  const a = new Date(`${TODAY}T00:00:00`);
  const b = new Date(`${dueDate}T00:00:00`);
  return Math.round((b.getTime() - a.getTime()) / 86_400_000);
}

"use client";

import * as React from "react";
import {
  IconAlertTriangle,
  IconBolt,
  IconCircleCheck,
  IconPackageExport,
  IconTruckDelivery,
  IconChevronRight,
  IconBuildingWarehouse,
} from "@tabler/icons-react";
import {
  Alert,
  AlertDescription,
  AlertTitle,
  Badge,
  Button,
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
  DataTable,
  Delta,
  Meter,
  NumberInput,
  ReferenceValue,
  SafetyBanner,
  ScanInput,
  Select,
  Separator,
  Sheet,
  SheetContent,
  SheetDescription,
  SheetFooter,
  SheetHeader,
  SheetTitle,
  Statistic,
  formatNumber,
  type ColumnDef,
  type ScanResult,
} from "@gunjo/ui";

import {
  ORDER_LINES,
  SKUS,
  STATUS_META,
  TODAY,
  availableToPromise,
  daysUntil,
  isAtRisk,
  lineStatus,
  type AllocStatus,
  type OrderLine,
  type Sku,
} from "./data";

// ---------------------------------------------------------------------------
// Working state: an editable copy of allocations keyed by order-line id, plus a
// "released" set. All derived numbers recompute from this on every render so the
// shortage / coverage view stays live as the coordinator allocates.
// ---------------------------------------------------------------------------

interface Row extends OrderLine {
  sku: Sku;
}

const SKU_BY_CODE = new Map(SKUS.map((s) => [s.code, s]));

function buildRows(
  allocations: Record<string, number>,
  released: Record<string, boolean>
): Row[] {
  return ORDER_LINES.map((line) => ({
    ...line,
    allocatedQty: allocations[line.id] ?? line.allocatedQty,
    released: released[line.id] ?? line.released,
    sku: SKU_BY_CODE.get(line.skuCode)!,
  }));
}

/** Per-SKU rollup of demand vs available stock, given current allocations. */
interface SkuRollup {
  sku: Sku;
  demand: number; // 全明細の受注数合計
  allocated: number; // この画面で引当済合計
  atp: number; // 引当可能残（実在庫 − 他引当 − 当画面引当）
  shortfall: number; // 未引当 demand に対して在庫が足りない量
}

function rollupBySku(rows: Row[]): Map<string, SkuRollup> {
  const map = new Map<string, SkuRollup>();
  for (const sku of SKUS) {
    map.set(sku.code, {
      sku,
      demand: 0,
      allocated: 0,
      atp: sku.onHand - sku.committedElsewhere,
      shortfall: 0,
    });
  }
  for (const row of rows) {
    const r = map.get(row.skuCode)!;
    r.demand += row.orderedQty;
    r.allocated += row.allocatedQty;
  }
  for (const r of map.values()) {
    r.atp = availableToPromise(r.sku, r.allocated);
    const unmetDemand = Math.max(0, r.demand - r.allocated);
    r.shortfall = Math.max(0, unmetDemand - Math.max(0, r.atp));
  }
  return map;
}

const yen = (n: number) => formatNumber(n);

export default function ShippingAllocation() {
  const [allocations, setAllocations] = React.useState<Record<string, number>>(
    {}
  );
  const [released, setReleased] = React.useState<Record<string, boolean>>({});
  const [openLineId, setOpenLineId] = React.useState<string | null>(null);
  const [statusFilter, setStatusFilter] = React.useState<AllocStatus | "all">(
    "all"
  );

  const rows = React.useMemo(
    () => buildRows(allocations, released),
    [allocations, released]
  );
  const skuRollup = React.useMemo(() => rollupBySku(rows), [rows]);

  // Each row's status depends on its SKU rollup shortfall.
  const rowStatus = React.useCallback(
    (row: Row): AllocStatus =>
      lineStatus(
        row.orderedQty,
        row.allocatedQty,
        skuRollup.get(row.skuCode)!.shortfall
      ),
    [skuRollup]
  );

  // ---- summary tiles ----
  const totals = React.useMemo(() => {
    let unallocated = 0;
    let shortage = 0;
    let atRisk = 0;
    let releasable = 0;
    for (const row of rows) {
      const st = rowStatus(row);
      if (st === "unallocated" || st === "partial") unallocated += 1;
      if (st === "shortage") shortage += 1;
      if (isAtRisk(row.dueDate, st)) atRisk += 1;
      if (st === "allocated" && !row.released) releasable += 1;
    }
    return { unallocated, shortage, atRisk, releasable };
  }, [rows, rowStatus]);

  const shortSkus = React.useMemo(
    () => [...skuRollup.values()].filter((r) => r.shortfall > 0),
    [skuRollup]
  );

  // ---- mutations ----
  const setAlloc = (id: string, qty: number) =>
    setAllocations((prev) => ({ ...prev, [id]: Math.max(0, qty) }));

  const autoAllocateAll = () => {
    // Greedy by priority then due date; never exceed ATP.
    const remainingAtp = new Map<string, number>();
    for (const sku of SKUS) {
      remainingAtp.set(sku.code, sku.onHand - sku.committedElsewhere);
    }
    // pre-charge currently-allocated amounts
    for (const row of rows) {
      remainingAtp.set(
        row.skuCode,
        (remainingAtp.get(row.skuCode) ?? 0) - row.allocatedQty
      );
    }
    const ordered = [...rows].sort((a, b) => {
      if (a.priority !== b.priority) return a.priority === "high" ? -1 : 1;
      return a.dueDate.localeCompare(b.dueDate);
    });
    const next: Record<string, number> = { ...allocations };
    for (const row of ordered) {
      if (row.released) continue;
      const need = row.orderedQty - row.allocatedQty;
      if (need <= 0) continue;
      const canGive = Math.min(need, Math.max(0, remainingAtp.get(row.skuCode) ?? 0));
      if (canGive > 0) {
        next[row.id] = row.allocatedQty + canGive;
        remainingAtp.set(row.skuCode, (remainingAtp.get(row.skuCode) ?? 0) - canGive);
      }
    }
    setAllocations(next);
  };

  const releaseLine = (id: string) =>
    setReleased((prev) => ({ ...prev, [id]: true }));

  const openRow = rows.find((r) => r.id === openLineId) ?? null;

  // ---- table columns ----
  const columns = React.useMemo<ColumnDef<Row>[]>(
    () => [
      {
        accessorKey: "orderNo",
        header: "出荷オーダ / 得意先",
        cell: ({ row }) => {
          const r = row.original;
          return (
            <div className="flex flex-col">
              <span className="font-medium tabular-nums">{r.orderNo}</span>
              <span className="text-xs text-muted-foreground">{r.customer}</span>
            </div>
          );
        },
      },
      {
        id: "sku",
        header: "品番 / 品名",
        cell: ({ row }) => {
          const r = row.original;
          return (
            <div className="flex flex-col">
              <span className="font-medium tabular-nums">{r.skuCode}</span>
              <span className="text-xs text-muted-foreground">{r.sku.name}</span>
            </div>
          );
        },
      },
      {
        accessorKey: "orderedQty",
        header: "受注数",
        cell: ({ row }) => (
          <span className="tabular-nums">{yen(row.original.orderedQty)}</span>
        ),
      },
      {
        id: "coverage",
        header: "引当 / 受注",
        cell: ({ row }) => {
          const r = row.original;
          const st = rowStatus(r);
          const tone =
            st === "allocated"
              ? "success"
              : st === "shortage"
                ? "destructive"
                : "warning";
          return (
            <div className="min-w-[140px]">
              <Meter
                value={r.allocatedQty}
                max={r.orderedQty}
                tone={tone}
                size="inline"
                label={`${r.orderNo} ${r.skuCode} 引当`}
                valueText={`受注 ${r.orderedQty} 個中 ${r.allocatedQty} 個 引当（${st === "shortage" ? "欠品" : st === "allocated" ? "引当済" : "未充足"}）`}
              />
              <span className="mt-0.5 block text-xs tabular-nums text-muted-foreground">
                {yen(r.allocatedQty)} / {yen(r.orderedQty)} 個
              </span>
            </div>
          );
        },
      },
      {
        id: "status",
        header: "引当状況",
        cell: ({ row }) => {
          const st = rowStatus(row.original);
          const m = STATUS_META[st];
          return (
            <Badge variant={m.badge} className="gap-1">
              <span aria-hidden className="leading-none">
                {m.symbol}
              </span>
              {m.label}
            </Badge>
          );
        },
      },
      {
        accessorKey: "dueDate",
        header: "出荷予定日",
        cell: ({ row }) => {
          const r = row.original;
          const st = rowStatus(r);
          const risk = isAtRisk(r.dueDate, st);
          const d = daysUntil(r.dueDate);
          return (
            <div className="flex flex-col">
              <span className="tabular-nums">{r.dueDate}</span>
              {risk ? (
                <span className="inline-flex items-center gap-1 text-xs font-medium text-destructive">
                  <IconAlertTriangle className="h-3 w-3 shrink-0" aria-hidden />
                  {d < 0 ? `${-d}日超過` : d === 0 ? "本日締切" : "遅延リスク"}
                  <span className="sr-only">出荷遅延リスクあり</span>
                </span>
              ) : (
                <span className="text-xs text-muted-foreground">
                  あと{d}日
                </span>
              )}
            </div>
          );
        },
      },
      {
        id: "action",
        header: "操作",
        cell: ({ row }) => {
          const r = row.original;
          const st = rowStatus(r);
          if (r.released) {
            return (
              <span className="inline-flex items-center gap-1 text-xs font-medium text-success-strong">
                <IconCircleCheck className="h-4 w-4 shrink-0" aria-hidden />
                出荷指示済
              </span>
            );
          }
          if (st === "allocated") {
            return (
              <Button
                size="sm"
                variant="success"
                onClick={() => releaseLine(r.id)}
              >
                <IconPackageExport className="h-4 w-4" aria-hidden />
                出荷指示
              </Button>
            );
          }
          return (
            <Button
              size="sm"
              variant="outline"
              onClick={() => setOpenLineId(r.id)}
            >
              引当
              <IconChevronRight className="h-4 w-4" aria-hidden />
            </Button>
          );
        },
      },
    ],
    [rowStatus]
  );

  const filteredRows = React.useMemo(() => {
    if (statusFilter === "all") return rows;
    return rows.filter((r) => rowStatus(r) === statusFilter);
  }, [rows, statusFilter, rowStatus]);

  return (
    <main className="mx-auto w-full max-w-7xl px-4 py-6 sm:px-6 lg:py-8">
      {/* ---- header ---- */}
      <header className="mb-6 flex flex-col gap-2">
        <div className="flex items-center gap-2 text-sm text-muted-foreground">
          <IconBuildingWarehouse className="h-4 w-4" aria-hidden />
          <span>東日本物流センター</span>
          <span aria-hidden>·</span>
          <span className="tabular-nums">基準日 {TODAY}</span>
        </div>
        <h1 className="text-2xl font-bold tracking-tight sm:text-3xl">
          出荷 / 在庫引当
        </h1>
        <p className="max-w-2xl text-sm text-muted-foreground">
          受注オーダに引当可能在庫を割り当て、欠品・出荷遅延リスクを把握して、
          引当済の明細を出荷指示（ピッキング）へ引き渡します。
        </p>
      </header>

      {/* ---- shortage alert (assertive, acknowledgeable) ---- */}
      {shortSkus.length > 0 ? (
        <div className="mb-6">
          <SafetyBanner
            tone="destructive"
            title={`欠品 ${shortSkus.length} 品目 — 受注を満たせません`}
            actions={
              <Button
                size="sm"
                variant="destructive"
                onClick={autoAllocateAll}
              >
                <IconBolt className="h-4 w-4" aria-hidden />
                可能な分を自動引当
              </Button>
            }
          >
            <ul className="mt-1 space-y-1">
              {shortSkus.map((r) => (
                <li
                  key={r.sku.code}
                  className="flex flex-wrap items-center gap-x-2 gap-y-0.5"
                >
                  <span className="font-medium tabular-nums">
                    {r.sku.code}
                  </span>
                  <span className="text-xs">{r.sku.name}</span>
                  <Delta
                    value={-r.shortfall}
                    format={(v) => `${yen(Math.abs(v))} 個`}
                    labels={{ negative: "不足" }}
                    showLabel
                  />
                </li>
              ))}
            </ul>
          </SafetyBanner>
        </div>
      ) : (
        <div className="mb-6">
          <Alert variant="success">
            <IconCircleCheck className="h-4 w-4" aria-hidden />
            <AlertTitle as="h2">欠品なし</AlertTitle>
            <AlertDescription>
              現在の受注はすべて引当可能在庫の範囲内です。
            </AlertDescription>
          </Alert>
        </div>
      )}

      {/* ---- summary tiles ---- */}
      <section aria-label="サマリ" className="mb-8">
        <div className="grid grid-cols-2 gap-3 lg:grid-cols-4">
          <Statistic
            label="未引当 / 一部引当"
            value={`${totals.unallocated} 明細`}
            hint="要対応"
            tone={totals.unallocated > 0 ? "negative" : "neutral"}
            trend={totals.unallocated > 0 ? "down" : "flat"}
          />
          <Statistic
            label="欠品明細"
            value={`${totals.shortage} 明細`}
            hint="在庫不足"
            tone={totals.shortage > 0 ? "negative" : "positive"}
            trend={totals.shortage > 0 ? "down" : "flat"}
          />
          <Statistic
            label="出荷遅延リスク"
            value={`${totals.atRisk} 明細`}
            hint="予定日が迫る/超過"
            tone={totals.atRisk > 0 ? "negative" : "positive"}
            trend={totals.atRisk > 0 ? "down" : "flat"}
          />
          <Statistic
            label="出荷指示待ち"
            value={`${totals.releasable} 明細`}
            hint="引当済・未引渡"
            tone={totals.releasable > 0 ? "positive" : "neutral"}
            trend="flat"
          />
        </div>
      </section>

      <div className="grid grid-cols-1 gap-8 lg:grid-cols-[1fr_360px]">
        {/* ---- order list ---- */}
        <section aria-labelledby="orders-heading">
          <div className="mb-3 flex flex-wrap items-end justify-between gap-3">
            <div>
              <h2 id="orders-heading" className="text-lg font-semibold">
                受注 / 出荷オーダ一覧
              </h2>
              <p className="text-xs text-muted-foreground">
                引当状況は記号 + ラベルで表示（色のみに依存しません）。
              </p>
            </div>
            <div className="flex items-end gap-2">
              <Select
                label="引当状況で絞り込み"
                value={statusFilter}
                onChange={(e) =>
                  setStatusFilter(e.target.value as AllocStatus | "all")
                }
                className="w-40"
              >
                <option value="all">すべて</option>
                <option value="unallocated">未引当</option>
                <option value="partial">一部引当</option>
                <option value="shortage">欠品</option>
                <option value="allocated">引当済</option>
              </Select>
              <Button variant="primary" onClick={autoAllocateAll}>
                <IconBolt className="h-4 w-4" aria-hidden />
                一括自動引当
              </Button>
            </div>
          </div>

          <DataTable
            columns={columns}
            data={filteredRows}
            pageSize={10}
            getRowState={(row) =>
              rowStatus(row) === "shortage" ? "selected" : undefined
            }
            renderCard={(row) => <OrderCard row={row} status={rowStatus(row)} onAllocate={() => setOpenLineId(row.id)} onRelease={() => releaseLine(row.id)} />}
          />
        </section>

        {/* ---- per-SKU allocation vs stock ---- */}
        <aside aria-labelledby="stock-heading" className="space-y-4">
          <div>
            <h2 id="stock-heading" className="text-lg font-semibold">
              引当 vs 在庫（品番別）
            </h2>
            <p className="text-xs text-muted-foreground">
              受注数・引当可能在庫・安全在庫の関係。マーカー線は安全在庫。
            </p>
          </div>

          {[...skuRollup.values()].map((r) => (
            <SkuStockCard key={r.sku.code} rollup={r} />
          ))}
        </aside>
      </div>

      {/* ---- pick / ship release by scan ---- */}
      <section aria-labelledby="release-heading" className="mt-10">
        <h2 id="release-heading" className="mb-1 text-lg font-semibold">
          ピッキング / 出荷指示（スキャン引き渡し）
        </h2>
        <p className="mb-3 text-xs text-muted-foreground">
          引当済の明細の品番バーコードをスキャンすると、出荷指示（ピッキング）へ引き渡します。
        </p>
        <ReleaseScanPanel rows={rows} status={rowStatus} onRelease={releaseLine} />
      </section>

      {/* ---- allocate sheet ---- */}
      <AllocateSheet
        row={openRow}
        rollup={openRow ? skuRollup.get(openRow.skuCode)! : null}
        onClose={() => setOpenLineId(null)}
        onChange={(qty) => openRow && setAlloc(openRow.id, qty)}
        onRelease={(id) => {
          releaseLine(id);
          setOpenLineId(null);
        }}
      />
    </main>
  );
}

// ---------------------------------------------------------------------------
// Per-SKU stock card — demand vs available, with safety-stock threshold.
// ---------------------------------------------------------------------------

function SkuStockCard({ rollup }: { rollup: SkuRollup }) {
  const { sku, demand, allocated, atp, shortfall } = rollup;
  const physical = sku.onHand - sku.committedElsewhere; // 引当に回せる総量
  return (
    <Card>
      <CardHeader className="p-4 pb-2">
        <div className="flex items-start justify-between gap-2">
          <div>
            <CardTitle as="h3" className="text-base tabular-nums">
              {sku.code}
            </CardTitle>
            <CardDescription className="text-xs">{sku.name}</CardDescription>
          </div>
          {shortfall > 0 ? (
            <Badge variant="destructive" className="gap-1 shrink-0">
              <span aria-hidden>▲</span>欠品
            </Badge>
          ) : (
            <Badge variant="success" className="gap-1 shrink-0">
              <span aria-hidden>●</span>充足
            </Badge>
          )}
        </div>
      </CardHeader>
      <CardContent className="space-y-3 p-4 pt-1">
        {/* 引当可能在庫 vs 安全在庫: ReferenceValue (value-vs-range), 在庫が
            安全在庫を割ると low/critical を表示。在庫は higher-is-better なので
            range.low に安全在庫を入れて「下回り」を警告に。 */}
        <div className="flex items-center justify-between text-sm">
          <span className="text-muted-foreground">引当可能在庫</span>
          <ReferenceValue
            value={atp}
            range={{ low: sku.safetyStock, criticalLow: 0 }}
            unit="個"
            labels={{ low: "安全在庫割れ", "critical-low": "在庫切れ" }}
            showLabel
            size="inline"
          />
        </div>

        {/* demand vs available をメーターで。max = max(demand, physical) で
            両方が見える。安全在庫を target マーカーに。 */}
        <Meter
          label={`${sku.code} 受注 vs 引当可能在庫`}
          value={allocated}
          max={Math.max(demand, physical, 1)}
          incoming={Math.max(0, Math.min(atp, demand - allocated))}
          target={sku.safetyStock}
          tone={shortfall > 0 ? "destructive" : allocated >= demand ? "success" : "warning"}
          unit="個"
          valueText={`受注 ${demand} 個、引当済 ${allocated} 個、引当可能 ${atp} 個、安全在庫 ${sku.safetyStock} 個${shortfall > 0 ? `、欠品 ${shortfall} 個` : ""}`}
        />

        <dl className="grid grid-cols-3 gap-2 text-center text-xs">
          <div>
            <dt className="text-muted-foreground">受注数</dt>
            <dd className="font-semibold tabular-nums">{yen(demand)}</dd>
          </div>
          <div>
            <dt className="text-muted-foreground">引当済</dt>
            <dd className="font-semibold tabular-nums">{yen(allocated)}</dd>
          </div>
          <div>
            <dt className="text-muted-foreground">不足</dt>
            <dd className="font-semibold tabular-nums">
              {shortfall > 0 ? (
                <Delta
                  value={-shortfall}
                  format={(v) => yen(Math.abs(v))}
                  labels={{ negative: "欠品" }}
                  hideArrow
                />
              ) : (
                <span className="text-success-strong">0</span>
              )}
            </dd>
          </div>
        </dl>
      </CardContent>
    </Card>
  );
}

// ---------------------------------------------------------------------------
// Allocate sheet — assign qty with live "after this allocation" preview.
// ---------------------------------------------------------------------------

function AllocateSheet({
  row,
  rollup,
  onClose,
  onChange,
  onRelease,
}: {
  row: Row | null;
  rollup: SkuRollup | null;
  onClose: () => void;
  onChange: (qty: number) => void;
  onRelease: (id: string) => void;
}) {
  // Draft quantity local to the sheet; commit on each change so the previews
  // (both here and the SKU card) recompute live.
  const open = row !== null && rollup !== null;

  if (!open) {
    return (
      <Sheet open={false} onOpenChange={(o) => !o && onClose()}>
        <SheetContent />
      </Sheet>
    );
  }

  const r = row!;
  const ro = rollup!;
  const physicalAvailable = ro.sku.onHand - ro.sku.committedElsewhere;
  // ATP excluding *this* line's current allocation = how much we could give this line.
  const atpExclThis = physicalAvailable - (ro.allocated - r.allocatedQty);
  const maxAssignable = Math.max(
    0,
    Math.min(r.orderedQty, atpExclThis)
  );
  const draft = r.allocatedQty;
  const remainingAfter = Math.max(0, r.orderedQty - draft);
  const fullyCovered = draft >= r.orderedQty;
  const exceedsStock = draft > maxAssignable;

  return (
    <Sheet open onOpenChange={(o) => !o && onClose()}>
      <SheetContent
        side="right"
        className="flex w-full flex-col gap-0 overflow-y-auto sm:max-w-md"
      >
        <SheetHeader>
          <SheetTitle>引当 — {r.orderNo}</SheetTitle>
          <SheetDescription>
            {r.customer} ／ {r.skuCode} {r.sku.name}
          </SheetDescription>
        </SheetHeader>

        <div className="mt-4 flex-1 space-y-5">
          {/* coverage of THIS line, with live incoming preview */}
          <div className="space-y-2">
            <Meter
              label="この明細の充足率"
              value={r.allocatedQty}
              max={r.orderedQty}
              tone={fullyCovered ? "success" : "warning"}
              unit="個"
            />
            <p className="text-xs text-muted-foreground tabular-nums">
              受注 {yen(r.orderedQty)} 個 ／ 引当 {yen(draft)} 個 ／ 残り{" "}
              {yen(remainingAfter)} 個
            </p>
          </div>

          <Separator />

          {/* SKU stock context, with incoming = this allocation preview */}
          <div className="space-y-2">
            <div className="flex items-center justify-between text-sm">
              <span className="font-medium">SKU 在庫への影響</span>
              <ReferenceValue
                value={ro.atp}
                range={{ low: ro.sku.safetyStock, criticalLow: 0 }}
                unit="個"
                labels={{ low: "安全在庫割れ", "critical-low": "在庫切れ" }}
                showLabel
                size="inline"
              />
            </div>
            <Meter
              label={`${r.skuCode} 引当可能在庫の消費`}
              value={ro.allocated}
              max={physicalAvailable}
              target={ro.sku.safetyStock}
              tone={ro.atp < ro.sku.safetyStock ? "warning" : "success"}
              unit="個"
              valueText={`引当可能在庫 ${physicalAvailable} 個中 ${ro.allocated} 個 引当済。安全在庫 ${ro.sku.safetyStock} 個。残 ${ro.atp} 個。`}
            />
            <p className="text-xs text-muted-foreground">
              この明細に割当可能な上限{" "}
              <span className="font-semibold tabular-nums text-foreground">
                {yen(maxAssignable)} 個
              </span>
              （引当可能在庫の範囲内）
            </p>
          </div>

          <Separator />

          {/* quantity control */}
          <div className="space-y-2">
            <NumberInput
              label="引当数量"
              description={`0 〜 ${yen(maxAssignable)} 個の範囲で指定`}
              value={draft}
              min={0}
              max={maxAssignable}
              step={1}
              layout="stepper"
              onValueChange={onChange}
            />
            <div className="flex flex-wrap gap-2">
              <Button
                size="sm"
                variant="outline"
                onClick={() => onChange(maxAssignable)}
                disabled={draft >= maxAssignable}
              >
                可能な上限まで（{yen(maxAssignable)} 個）
              </Button>
              <Button
                size="sm"
                variant="ghost"
                onClick={() => onChange(0)}
                disabled={draft === 0}
              >
                引当解除
              </Button>
            </div>
          </div>

          {exceedsStock ? (
            <Alert variant="destructive">
              <IconAlertTriangle className="h-4 w-4" aria-hidden />
              <AlertTitle as="h3">引当可能在庫を超過</AlertTitle>
              <AlertDescription>
                指定数量が引当可能在庫を超えています。上限{" "}
                {yen(maxAssignable)} 個までに調整してください。
              </AlertDescription>
            </Alert>
          ) : remainingAfter > 0 ? (
            <Alert variant="warning">
              <IconAlertTriangle className="h-4 w-4" aria-hidden />
              <AlertTitle as="h3">未充足あり</AlertTitle>
              <AlertDescription>
                受注数に対して {yen(remainingAfter)} 個 不足しています。
                {maxAssignable < r.orderedQty
                  ? "在庫不足のため全量引当できません（欠品）。"
                  : ""}
              </AlertDescription>
            </Alert>
          ) : (
            <Alert variant="success">
              <IconCircleCheck className="h-4 w-4" aria-hidden />
              <AlertTitle as="h3">全量引当済</AlertTitle>
              <AlertDescription>
                出荷指示（ピッキング）へ引き渡せます。
              </AlertDescription>
            </Alert>
          )}
        </div>

        <SheetFooter className="mt-6">
          <Button variant="outline" onClick={onClose}>
            閉じる
          </Button>
          <Button
            variant="success"
            disabled={!fullyCovered || r.released}
            onClick={() => onRelease(r.id)}
          >
            <IconPackageExport className="h-4 w-4" aria-hidden />
            出荷指示へ
          </Button>
        </SheetFooter>
      </SheetContent>
    </Sheet>
  );
}

// ---------------------------------------------------------------------------
// Release-by-scan panel. Scan a SKU barcode → release the next allocated,
// unreleased line for that SKU to picking. ScanInput is built for exactly this
// (goods-receiving / pick-confirm): types code + Enter, announces the result.
// ---------------------------------------------------------------------------

function ReleaseScanPanel({
  rows,
  status,
  onRelease,
}: {
  rows: Row[];
  status: (row: Row) => AllocStatus;
  onRelease: (id: string) => void;
}) {
  const handleScan = (code: string): ScanResult => {
    const sku = SKUS.find((s) => s.barcode === code || s.code === code);
    if (!sku) {
      return { ok: false, message: `未登録のコードです: ${code}` };
    }
    const target = rows.find(
      (r) =>
        r.skuCode === sku.code && !r.released && status(r) === "allocated"
    );
    if (!target) {
      const pending = rows.find(
        (r) => r.skuCode === sku.code && !r.released && status(r) !== "allocated"
      );
      if (pending) {
        return {
          ok: false,
          message: `${sku.code} は引当が未完了です（出荷指示できません）`,
        };
      }
      return {
        ok: false,
        message: `${sku.code} に出荷指示待ちの明細はありません`,
      };
    }
    onRelease(target.id);
    return {
      ok: true,
      message: `${target.orderNo}（${sku.code}）を出荷指示へ引き渡しました`,
    };
  };

  const releasable = rows.filter(
    (r) => !r.released && status(r) === "allocated"
  ).length;

  return (
    <Card>
      <CardContent className="p-4">
        <div className="mb-3 flex items-center gap-2 text-sm text-muted-foreground">
          <IconTruckDelivery className="h-4 w-4" aria-hidden />
          出荷指示待ち{" "}
          <span className="font-semibold tabular-nums text-foreground">
            {releasable} 明細
          </span>
        </div>
        <ScanInput
          label="品番 / バーコードをスキャン"
          description="ハンディ端末でスキャン、または入力して Enter。引当済の明細のみ引き渡せます。"
          assertive
          showFeed
          onScan={handleScan}
          placeholder="例: 4901234500017 または SKU-A100"
        />
      </CardContent>
    </Card>
  );
}

// ---------------------------------------------------------------------------
// Mobile card for the DataTable's renderCard (< md).
// ---------------------------------------------------------------------------

function OrderCard({
  row,
  status,
  onAllocate,
  onRelease,
}: {
  row: Row;
  status: AllocStatus;
  onAllocate: () => void;
  onRelease: () => void;
}) {
  const m = STATUS_META[status];
  const risk = isAtRisk(row.dueDate, status);
  const d = daysUntil(row.dueDate);
  return (
    <div className="flex flex-col gap-3 rounded-lg border bg-card p-4">
      <div className="flex items-start justify-between gap-2">
        <div>
          <p className="font-medium tabular-nums">{row.orderNo}</p>
          <p className="text-xs text-muted-foreground">{row.customer}</p>
        </div>
        <Badge variant={m.badge} className="gap-1 shrink-0">
          <span aria-hidden>{m.symbol}</span>
          {m.label}
        </Badge>
      </div>
      <div>
        <p className="text-sm font-medium tabular-nums">{row.skuCode}</p>
        <p className="text-xs text-muted-foreground">{row.sku.name}</p>
      </div>
      <Meter
        value={row.allocatedQty}
        max={row.orderedQty}
        tone={
          status === "allocated"
            ? "success"
            : status === "shortage"
              ? "destructive"
              : "warning"
        }
        size="inline"
        label={`${row.orderNo} 引当`}
        valueText={`受注 ${row.orderedQty} 個中 ${row.allocatedQty} 個 引当`}
      />
      <div className="flex items-center justify-between text-xs">
        <span className="tabular-nums text-muted-foreground">
          出荷予定 {row.dueDate}
        </span>
        {risk ? (
          <span className="inline-flex items-center gap-1 font-medium text-destructive">
            <IconAlertTriangle className="h-3 w-3" aria-hidden />
            {d < 0 ? `${-d}日超過` : d === 0 ? "本日締切" : "遅延リスク"}
          </span>
        ) : (
          <span className="text-muted-foreground">あと{d}日</span>
        )}
      </div>
      {row.released ? (
        <span className="inline-flex items-center gap-1 text-xs font-medium text-success-strong">
          <IconCircleCheck className="h-4 w-4" aria-hidden />
          出荷指示済
        </span>
      ) : status === "allocated" ? (
        <Button size="sm" variant="success" onClick={onRelease}>
          <IconPackageExport className="h-4 w-4" aria-hidden />
          出荷指示
        </Button>
      ) : (
        <Button size="sm" variant="outline" onClick={onAllocate}>
          引当する
          <IconChevronRight className="h-4 w-4" aria-hidden />
        </Button>
      )}
    </div>
  );
}
